// 지속 추세 LLM 프롬프트 생성 (Template C)
const item = $input.first().json;

const llmPrompt = `시스템: ${item.display_name} (${item.system_name})
분석 기간: 최근 8시간 중 ${item.anomaly_hours}시간 이상 감지
수집기: ${item.collector_type} / ${item.metric_group}
최고 심각도: ${item.worst_severity}

[시간별 추세 흐름]
${item.trend_sequence || '추세 데이터 없음'}

[기존 예측 목록]
${item.predictions || '예측 없음'}

이 시스템이 지속적으로 이상 상태를 보이고 있습니다.
임계치 도달 예상 시점과 조치 우선순위를 다음 JSON 형식으로만 응답해 주세요:
{
  "hours_to_breach": 숫자 또는 null,
  "breach_metric": "임계치에 먼저 도달할 메트릭명",
  "severity": "warning 또는 critical 중 하나",
  "trend_summary": "지속 추세 요약 (1문장)",
  "immediate_actions": "즉시 조치 사항 (1~2문장)"
}`;

return [{ json: { ...item, llm_prompt: llmPrompt } }];

// LLM 응답 파싱 및 프로액티브 알림 카드 생성
const llmResp = $input.first().json;
const prevData = $('지속 추세 LLM 프롬프트 생성').first().json;

let llmResult = {};
try {
  const content = llmResp?.choices?.[0]?.message?.content 
    || llmResp?.response 
    || llmResp?.content 
    || '{}';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  llmResult = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch(e) {
  llmResult = { severity: 'warning', trend_summary: '분석 실패', hours_to_breach: null };
}

const severity    = llmResult.severity || 'warning';
const colorMap    = { critical: 'Attention', warning: 'Warning', normal: 'Good' };
const color       = colorMap[severity] || 'Warning';
const hoursText   = llmResult.hours_to_breach ? `약 ${llmResult.hours_to_breach}시간 후` : '예측 불가';

const card = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        {
          type: 'TextBlock',
          text: `🔴 [장애 예방] ${prevData.display_name} 지속 이상 감지`,
          weight: 'Bolder',
          size: 'Medium',
          color: color
        },
        {
          type: 'FactSet',
          facts: [
            { title: '시스템',       value: `${prevData.display_name} (${prevData.system_name})` },
            { title: '수집기',       value: `${prevData.collector_type} / ${prevData.metric_group}` },
            { title: '지속 이상',    value: `최근 8시간 중 ${prevData.anomaly_hours}시간` },
            { title: '추세',         value: llmResult.trend_summary || '-' },
            { title: '임계치 예상',  value: `${llmResult.breach_metric || '-'} — ${hoursText}` },
            { title: '즉시 조치',    value: llmResult.immediate_actions || '-' }
          ]
        }
      ]
    }
  }]
};

const webhookUrl = prevData.teams_webhook_url || $env.TEAMS_WEBHOOK_URL;

return [{ json: { ...prevData, llm_result: llmResult, teams_card: JSON.stringify(card), webhook_url: webhookUrl } }];
